import { useState, useEffect } from 'react';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [projects, setProjects] = useState([]);
  const [projectTaskMap, setProjectTaskMap] = useState({});
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  const fetchData = async () => {
    try {
      setLoading(true);

      if (user?.role === 'admin') {
        const projectsRes = await API.get('/projects');
        const allProjects = projectsRes.data; // ✅ FIXED

        setProjects(allProjects);

        const taskPromises = allProjects.map(p =>
          API.get(`/tasks?project=${p._id}`)
        );

        const taskResults = await Promise.all(taskPromises);
        const allTasks = taskResults.flatMap(r => r.data.tasks);

        setTasks(allTasks);

        const map = {};
        allProjects.forEach((p, i) => {
          map[p._id] = {
            name: p.name,
            tasks: taskResults[i].data.tasks,
          };
        });

        setProjectTaskMap(map);

      } else {
        const [tasksRes, projectsRes] = await Promise.all([
          API.get('/tasks/my-tasks'),
          API.get('/projects'),
        ]);

        const myTasks = tasksRes.data.tasks;
        const myProjects = projectsRes.data; // ✅ FIXED

        setTasks(myTasks);
        setProjects(myProjects);

        const map = {};
        myProjects.forEach(p => {
          const projectTasks = myTasks.filter(
            t => t.project?._id === p._id || t.project === p._id
          );
          map[p._id] = { name: p.name, tasks: projectTasks };
        });

        setProjectTaskMap(map);
      }

    } catch (err) {
      console.error('Dashboard error:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [user]);

  // 🔥 PROGRESS-BASED STATS (FIXED)
  const total = tasks.length;
  const done = tasks.filter(t => t.progress === 100).length;
  const inProgress = tasks.filter(t => t.progress > 0 && t.progress < 100).length;
  const todo = tasks.filter(t => !t.progress || t.progress === 0).length;

  const overdue = tasks.filter(t =>
    t.dueDate &&
    new Date(t.dueDate) < new Date() &&
    t.progress !== 100
  ).length;

  const avgProgress = total > 0
    ? Math.round(tasks.reduce((sum, t) => sum + (t.progress || 0), 0) / total)
    : 0;

  if (loading) return <p>Loading...</p>;

  return (
    <div style={{ maxWidth: '900px', margin: 'auto' }}>

      <h2>Welcome {user?.name}</h2>

      {/* Stats */}
      <div style={{ display: 'flex', gap: '15px', marginBottom: '20px' }}>
        <Stat label="Total" value={total} />
        <Stat label="Todo" value={todo} />
        <Stat label="In Progress" value={inProgress} />
        <Stat label="Done" value={done} />
        <Stat label="Overdue" value={overdue} />
      </div>

      {/* Overall Progress */}
      <div style={{ marginBottom: '20px' }}>
        <strong>Overall Progress: {avgProgress}%</strong>
        <div style={{ height: '10px', background: '#ddd', borderRadius: '5px' }}>
          <div style={{
            width: `${avgProgress}%`,
            height: '100%',
            background: '#6366f1',
            borderRadius: '5px'
          }} />
        </div>
      </div>

      {/* Project Progress */}
      <h3>My Projects</h3>

      {Object.entries(projectTaskMap).length === 0 ? (
        <p>No projects yet</p>
      ) : (
        Object.entries(projectTaskMap).map(([id, proj]) => {
          const total = proj.tasks.length;
          const done = proj.tasks.filter(t => t.progress === 100).length;
          const pct = total ? Math.round((done / total) * 100) : 0;

          return (
            <div key={id} style={{ marginBottom: '15px' }}>
              <strong>{proj.name}</strong>

              <div style={{ height: '8px', background: '#eee', marginTop: '5px' }}>
                <div style={{
                  width: `${pct}%`,
                  height: '100%',
                  background: '#10b981'
                }} />
              </div>

              <small>{pct}% completed</small>
            </div>
          );
        })
      )}

    </div>
  );
};

const Stat = ({ label, value }) => (
  <div style={{
    background: '#f4f4f4',
    padding: '15px',
    borderRadius: '10px',
    textAlign: 'center',
    flex: 1
  }}>
    <h3>{value}</h3>
    <p>{label}</p>
  </div>
);

export default Dashboard;
